function percorrerLista(lista, acao) {
  for (let i = 0; i < lista.length; i = i + 1) {
    acao(lista[i]);
  }
}

percorrerLista([1, 2, 3], function (item) {
  console.log(item);
});

function transformarLista(lista, transformacao) {
  const resultado = [];

  for (let i = 0; i < lista.length; i = i + 1) {
    resultado.push(transformacao(lista[i]));
  }

  return resultado;
}

const dobrados = transformarLista([1, 2, 3], function (numero) {
  return numero * 2;
});

console.log(dobrados);
